scwin.onpageload = function () {
  scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
  let now = new Date();
  let hof = String(now.getHours()).padStart(2, "0");
  let mm = String(now.getMinutes()).padStart(2, "0");
  scwin.currentTime = hof + mm;
  scwin.userId = $c.ses.getUserId();
  scwin.userNm = $c.ses.getUserNm();
  scwin.vLobranCd = $c.ses.getLobranCd();
  scwin.vLobranNm = $c.ses.getLobranNm();
  scwin.params = $c.data.getParameter($p);
  if (scwin.params != null) {
    scwin.v_linkcheck = scwin.params["linkcheck"] || "0";
    scwin.v_kcomcd = scwin.params["kcomcd"] || "";
    scwin.v_blno = scwin.params["blno"] || "";
    scwin.v_mhno = scwin.params["mhno"] || "";
    scwin.v_bkno = scwin.params["bkno"] || "";
  } else {
    scwin.v_linkcheck = "0";
  }
  scwin.f_DefaultValue();
  scwin.f_Check();
  scwin.f_ContainerTypeLoading();
  scwin.f_getParametrSetting(scwin.v_linkcheck);
};
scwin.onUdcCompleted = function () {};
scwin.f_getParametrSetting = function (gubun) {
  switch (gubun) {
    case "0":
      break;
    case "1":
      let lv_kcomcd = scwin.v_kcomcd;
      let lv_bkno = scwin.v_bkno;
      if (lv_bkno == "null" || lv_bkno == "") {
        cnd_ed_bkNo.setValue("");
        cnd_ed_bkNo.setFocus();
        return false;
      }
      scwin.hd_kcomcd = lv_kcomcd;
      cnd_ed_bkNo.setValue(lv_bkno);
      scwin.f_Retrieve();
      break;
  }
};
scwin.f_Check = function () {
  ed_cnttype1.setValue("22GP");
  ed_cnttype2.setValue("42GP");
  ed_cnttype3.setValue("45GP");
  lc_cfs.setValue("F");
  chb_iptYn.setValue("");
  chb_triYn.setValue("");
};
scwin.f_DefaultValue = function () {
  scwin.f_initSetTab();
  scwin.f_Set("INIT");
  cnd_ed_bkNo.setFocus();
  scwin.processFlag = "T";
};
scwin.f_initSetTab = function () {
  $c.gus.cfEnableObjects($p, [btn_Find, btn_HouseBl, btn_DirectBl]);
  // TODO: cfViewTab(0) - tab control
};
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_Print, btn_HouseBl, btn_DirectBl, btn_OrderSendDel, btn_OrderSend, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
      $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Find]);
      scwin.f_DisablePopUpObj();
      $c.gus.cfEnableObjects($p, [cnd_ed_bkNo]);
      scwin.statusFlag = "I";
      break;
    case "RETRIEVE":
      $c.gus.cfDisableKeyData($p);
      scwin.f_DisablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
      $c.gus.cfEnableBtnOnly($p, [btn_Copy, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_Find, btn_HouseBl, btn_DirectBl]);
      gr_containerDoorOrder.setColumnVisible("chk", true);
      gr_containerDoorOrderQty.setReadOnly("grid", true);
      gr_containerBookingCont.setReadOnly("grid", true);
      if (scwin.statusFlag == "C") {
        $c.gus.cfDisableBtnOnly($p, [btn_Update]);
      } else {
        $c.gus.cfEnableBtnOnly($p, [btn_Update]);
      }
      $c.gus.cfEnableObjects($p, [cnd_ed_bkNo]);
      scwin.statusFlag = "";
      break;
    case "CREATE":
      $c.gus.cfEnableKeyData($p);
      scwin.f_EnablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Create, btn_Update, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_DirectBl]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_Find, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
      gr_containerDoorOrder.setColumnVisible("chk", false);
      gr_containerDoorOrderQty.setReadOnly("grid", false);
      gr_containerBookingCont.setReadOnly("grid", false);
      $c.gus.cfDisableObjects($p, [cnd_ed_bkNo]);
      scwin.statusFlag = "C";
      break;
    case "UPDATE":
      dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
      dma_retrieve.set("bkNo", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkNo"));
      dma_retrieve.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
      $c.sbm.execute($p, sbm_retrievebookingHbl);
      if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
        $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Update, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_DirectBl]);
        $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_Find, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
        $c.gus.cfDisableKey($p);
        scwin.f_EnablePopUpObj();
        gr_containerDoorOrder.setColumnVisible("chk", false);
        gr_containerDoorOrderQty.setReadOnly("grid", false);
        gr_containerBookingCont.setReadOnly("grid", false);
        $c.gus.cfDisableObjects($p, [cnd_ed_bkNo]);
        scwin.statusFlag = "U";
      } else {
        $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Update, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_DirectBl]);
        $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_Find, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
        $c.gus.cfDisableKeyData($p);
        scwin.f_DisablePopUpObj2();
        $c.gus.cfEnableObjects($p, [chb_triYn, lc_triItemType, ed_triWrkDesc, txt_bkPicNm, ed_ts1VsslCd, txt_ts1VsslNm, ed_ts2VsslCd, txt_ts2VsslNm, ed_ts1Voy, ed_ts2Voy, ed_ts1PortCd, txt_ts1PortNm, ed_ts2PortCd, txt_ts2PortNm, ica_ts1Etd, ica_ts1Eta, ica_ts2Etd, ica_ts2Eta, txt_remarkMaster, ed_refSellingAmt, ed_refBuyingAmt, ed_freeDay]);
        gr_containerDoorOrder.setReadOnly("grid", true);
        gr_containerDoorOrderQty.setReadOnly("grid", true);
        gr_containerBookingCont.setReadOnly("grid", true);
        $c.gus.cfDisableObjects($p, [cnd_ed_bkNo]);
        scwin.statusFlag = "U";
      }
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Delete, btn_Cancel, btn_Print]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Create]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};
