scwin.f_selectTabMenu = function (idx) {
  switch (idx) {
    case 0:
      scwin.tabIndex = 0;
      break;
    case 1:
      scwin.tabIndex = 1;
      if (ds_containerDoorOrder.getRowCount() == 0) {
        scwin.f_autoCreateDoorOrderInfo();
      }
      break;
  }
};
scwin.f_Retrieve = async function () {
  if (cnd_ed_bkNo.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_056, ["Booking No"]);
    return;
  } else {
    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("bkNo", cnd_ed_bkNo.getValue());
    dma_retrieve.set("bkbltype", scwin.hd_bkbltype);
    await $c.sbm.execute($p, sbm_retrieve);
    cnd_ed_bkNo.setFocus();
  }
};
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, cnd_ed_bkNo);
};
scwin.f_Create = function () {
  scwin.f_Set("CREATE");
  cnd_ed_bkNo.setValue("");
  ds_containerBookingList.insertRow();
  ds_containerDoorOrder.removeAll();
  ds_containerDoorOrderQty.removeAll();
  ds_containerBookingCont.removeAll();
  ds_houseblList.removeAll();
  scwin.f_Check();
  let row = ds_containerBookingList.getRowPosition();
  ds_containerBookingList.setCellData(row, "reDt", scwin.vCurDate);
  ds_containerBookingList.setCellData(row, "bkPic", scwin.userId);
  ds_containerBookingList.setCellData(row, "bkPicNm", scwin.userNm);
  if (!(scwin.vLobranCd == "null" || scwin.vLobranCd == null || scwin.vLobranCd == "")) {
    ds_containerBookingList.setCellData(row, "dept", scwin.vLobranCd);
    ds_containerBookingList.setCellData(row, "deptnm", scwin.vLobranNm);
  }
  ds_containerBookingList.setCellData(row, "etRsltsDt", "");
};
scwin.f_Update = async function () {
  let row = ds_containerBookingList.getRowPosition();
  if (row < 0 || ds_containerBookingList.getCellData(row, "bkNo") == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["HEADER"]);
    return;
  } else {
    scwin.f_Set("UPDATE");
  }
};
scwin.f_Save = async function () {
  if (ds_containerBookingList.isUpdated() || ds_containerDoorOrder.isUpdated() || ds_containerDoorOrderQty.isUpdated() || ds_containerBookingCont.isUpdated()) {
    if (await scwin.f_validate()) {
      let chk = await $c.win.confirm($p, E_MSG_CM_CRM_001);
      if (chk) {
        let bkRow = ds_containerBookingList.getRowPosition();
        if (ds_containerBookingList.getCellData(bkRow, "bkNo") == "") {
          if (ds_containerBookingList.getCellData(bkRow, "bkPic") == "" && ds_containerBookingList.getCellData(bkRow, "docPic") == "") {
            await $c.win.alert($p, "Booking담당자/Doc담당자 중 한 가지는 필수로 입력하여야 합니다.");
            return false;
          }
          dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
          if (ds_containerBookingList.getCellData(bkRow, "etRsltsDt") == "") {
            dma_retrieve.set("bkEtd", ds_containerBookingList.getCellData(bkRow, "bkEtd"));
            ds_containerBookingList.setCellData(bkRow, "etRsltsDt", ds_containerBookingList.getCellData(bkRow, "bkEtd"));
          } else {
            dma_retrieve.set("bkEtd", ds_containerBookingList.getCellData(bkRow, "etRsltsDt"));
          }
          if (ds_containerBookingList.getCellData(bkRow, "bkPic") == "") {
            ds_containerBookingList.setCellData(bkRow, "bkPic", scwin.userId);
            ds_containerBookingList.setCellData(bkRow, "bkPicNm", scwin.userNm);
          }
          await $c.sbm.execute($p, sbm_retrievebookingNo);
          let noRow = ds_retrieveNo.getRowPosition();
          if (noRow >= 0) {
            ds_containerBookingList.setCellData(bkRow, "bkNo", ds_retrieveNo.getCellData(noRow, "bkNo"));
          }
        }
        dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
        dma_retrieve.set("bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
        dma_retrieve.set("seq", ds_containerDoorOrder.getRowCount() > 0 ? ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq") : "");
        await $c.sbm.execute($p, sbm_retrievebookingHbl);
        if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
          ds_containerBookingList.setCellData(bkRow, "kcomcd", scwin.hd_kcomcd);
          ds_containerBookingList.setCellData(bkRow, "bkbltype", scwin.hd_bkbltype);
          ds_containerBookingList.setCellData(bkRow, "bkEtd", ed_bkEtd.getValue());
          ds_containerBookingList.setCellData(bkRow, "inpid", scwin.userId);
          if (ds_containerDoorOrder.getRowCount() == 0) {
            scwin.f_autoCreateDoorOrderInfo();
          } else {
            let dqRow = ds_containerDoorOrderQty.getRowPosition();
            if (dqRow >= 0) ds_containerDoorOrderQty.setCellData(dqRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
            let doRow = ds_containerDoorOrder.getRowPosition();
            if (doRow >= 0) ds_containerDoorOrder.setCellData(doRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
          }
          await $c.sbm.execute($p, sbm_save);
        } else {
          await $c.sbm.execute($p, sbm_save);
        }
        scwin.f_Set("SAVE");
        cnd_ed_bkNo.setValue(ds_containerBookingList.getCellData(bkRow, "bkNo"));
        scwin.f_Retrieve();
      }
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["Container Booking"]);
  }
};
scwin.f_Cancel = function () {
  if (scwin.statusFlag == "C") {
    scwin.f_Set("INIT");
  } else {
    scwin.f_Set("RETRIEVE");
    ds_containerBookingList.undoAll();
    ds_ctrtNo.undoAll();
    scwin.f_cancelRow(1);
    scwin.f_cancelRow(2);
    scwin.f_cancelRow(3);
    cnd_ed_bkNo.setFocus();
    scwin.processFlag = "T";
  }
};
