scwin.f_RunExcel = async function (dataId, gridId) {
  let countA = dataId.getRowCount();
  if (!(countA > 0)) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  let sheetName = "";
  let fileName = "";
  if (gridId == "gr_houseblList") {
    sheetName = "Booking List";
    fileName = "Booking List.xls";
  } else if (gridId == "gr_containerDoorOrder") {
    sheetName = "Door Order List";
    fileName = "Booking List.xls";
  }
  let chk = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
  if (chk) {
    $c.data.downloadGridViewExcel($p, gridId, {
      fileName: fileName,
      sheetName: sheetName
    });
  }
};
